key_js_patterns.load_and_index:
async function loadGame() {
  const res = await fetch("data/CHS_2024_game_v2.json");
  const data = await res.json();
  state.scenes = Object.fromEntries(data.scenes.map(s => [s.id, s]));
  state.flags  = Object.fromEntries(data.context_flags_system.flags.map(f => [f.id, false]));
  state.scores = { community_trust: 0, staff_wellbeing: 0, program_quality: 0, accountability: 0 };
  state.currentSceneId = "prologue";
  renderScene(state.scenes["prologue"]);
}

key_js_patterns.apply_option:
function applyOption(option) {
  // Apply score changes
  for (const [dim, val] of Object.entries(option.score_changes || {})) {
    state.scores[dim] = (state.scores[dim] || 0) + val;
  }
  // Set context flag
  if (option.sets_flag) state.flags[option.sets_flag] = true;
  // Navigate to consequence scene
  state.currentSceneId = option.consequence_scene_id;
  renderScene(state.scenes[option.consequence_scene_id]);
}

key_js_patterns.full_screen_canvas:
/* style.css */
html, body { margin: 0; background: #1A2028; display: flex;
             align-items: center; justify-content: center;
             width: 100%; height: 100%; overflow: hidden; }
#gameCanvas { image-rendering: pixelated;
              image-rendering: crisp-edges;
              width: 100vmin; height: calc(100vmin * 9/16);
              max-width: 100vw; max-height: 100vh; }
/* This scales the 320×180 pixel canvas to fill any screen
   while preserving integer-like sharpness via pixelated rendering */

key_js_patterns.gif_sprites:
/* GIF character sprites are layered over the canvas using absolute-positioned
   <img> elements inside a #sprite-layer div that overlays #gameCanvas.
   The div uses the same dimensions and CSS transform scale as the canvas.
   Each character GIF (48×48 px) is positioned in canvas-pixel coordinates
   and rendered at the same CSS scale as the canvas. */
function placeSprite(charId, x, y) {
  const img = document.getElementById("sprite-" + charId);
  img.style.left  = (x / 320 * 100) + "%";
  img.style.bottom = (y / 180 * 100) + "%";
}
